+
+    #[test]
+    fn parse_error_random_text() {
+        assert!(parse_dot("hello world").is_err());
+    }
+
+    #[test]
+    fn parse_error_empty_input() {
+        assert!(parse_dot("").is_err());
+    }
+
+    #[test]
+    fn parse_error_whitespace_only() {
+        assert!(parse_dot("   \n\t  ").is_err());
+    }
